// // This module implements a master-slave D-latch where the master samples D on CLK rising edge and the slave updates Q on CLK falling edge.
module master_slave_d_latch (  
    input wire D,  
    input wire CLK,  
    output reg Q  
);  
    reg master;  
    always @(posedge CLK) begin  
        master <= D;  
    end  
    always @(negedge CLK) begin  
        Q <= master;  
    end  
endmodule
